def verify_checksum(file_path, expected_checksum):
    algorithm, expected_hash = expected_checksum.split(":", 1)
    
    if algorithm not in hashlib.algorithms_available:
        raise ValueError(f"Unsupported hash algorithm: {algorithm}")
    
    hash_obj = hashlib.new(algorithm)
    
    with open(file_path, "rb") as f:
        while chunk := f.read(8192):
            hash_obj.update(chunk)
    
    actual_hash = hash_obj.hexdigest()
    
    if actual_hash != expected_hash:
        raise ValueError(f"Checksum mismatch for {file_path}. Expected: {expected_hash}, Got: {actual_hash}")
    
    return True


def download_resource(url, destination, checksum=None, timeout=30):
    destination = Path(destination)
    destination.parent.mkdir(parents=True, exist_ok=True)
    
    if destination.exists() and checksum:
        try:
            if verify_checksum(destination, checksum):
                print(f"Resource already exists and verified: {destination}")
                return
        except ValueError:
            print(f"Existing resource failed verification, re-downloading: {destination}")
            destination.unlink()
    
    if not url.startswith(("https://", "http://")):
        raise ValueError(f"Invalid URL scheme: {url}")
    
    print(f"Downloading resource from {url} to {destination}")
    
    try:
        req = urllib.request.Request(url)
        req.add_header("User-Agent", f"{PACKAGE_NAME}/{VERSION}")
        
        with urllib.request.urlopen(req, timeout=timeout) as response:
            if response.status != 200:
                raise urllib.error.HTTPError(url, response.status, "HTTP Error", response.headers, None)
            
            temp_file = destination.with_suffix(destination.suffix + ".tmp")
            
            with open(temp_file, "wb") as f:
                while chunk := response.read(8192):
                    f.write(chunk)
            
            if checksum:
                verify_checksum(temp_file, checksum)
            
            temp_file.rename(destination)
            print(f"Successfully downloaded: {destination}")
            
    except urllib.error.URLError as e:
        raise RuntimeError(f"Failed to download resource from {url}: {e}")
    except Exception as e:
        if temp_file.exists():
            temp_file.unlink()
        raise RuntimeError(f"Error downloading resource: {e}")


def create_directories():
    data_dir = get_package_data_dir()
    config_dir = get_config_dir()
    
    directories = [
        data_dir,
        data_dir / "models",
        data_dir / "cache",
        data_dir / "logs",
        config_dir,
    ]
    
    for directory in directories:
        directory.mkdir(parents=True, exist_ok=True)
        print(f"Created directory: {directory}")
    
    return data_dir, config_dir


def setup_environment_variables(data_dir, config_dir):
    env_vars = {
        f"{PACKAGE_NAME.upper()}_DATA_DIR": str(data_dir),
        f"{PACKAGE_NAME.upper()}_CONFIG_DIR": str(config_dir),
        f"{PACKAGE_NAME.upper()}_VERSION": VERSION,
    }
    
    env_file = config_dir / "environment.json"
    
    with open(env_file, "w") as f:
        json.dump(env_vars, f, indent=2)
    
    print(f"Environment configuration saved to: {env_file}")
    print("\nEnvironment variables to set:")
    for key, value in env_vars.items():
        print(f"  export {key}={value}")
    
    return env_vars


def download_resources(data_dir):
    for resource_name, resource_info in RESOURCES_MANIFEST.items():
        url = resource_info["url"]
        checksum = resource_info.get("checksum")
        destination = data_dir / resource_info["destination"]
        
        try:
            download_resource(url, destination, checksum)
        except Exception as e:
            print(f"Warning: Failed to download {resource_name}: {e}")
            print("You may need to download this resource manually.")


